// 第一步：搜索请求，拿到 searchid
let new_url = java.get('https://bcshuku.com/e/search/index.php?keyboard='+key+'&show=title,writer,byr&searchget=1',{
    "accept": "text/html,application/xhtml+xml,application/xml;q=0.9,image/avif,image/webp,image/apng,*/*;q=0.8,application/signed-exchange;v=b3;q=0.7",
    "accept-language": "zh-CN,zh;q=0.9,en;q=0.8,en-GB;q=0.7,en-US;q=0.6",
    "cache-control": "no-cache",
    "pragma": "no-cache",
    "referer": "https://bcshuku.com",
    "sec-ch-ua": "\"Microsoft Edge\";v=\"143\", \"Chromium\";v=\"143\", \"Not A(Brand\";v=\"24\"",
    "sec-ch-ua-mobile": "?1",
    "sec-ch-ua-platform": "\"Android\"",
    "sec-fetch-dest": "document",
    "sec-fetch-mode": "navigate",
    "sec-fetch-site": "same-origin",
    "sec-fetch-user": "?1",
    "upgrade-insecure-requests": "1",
    "user-agent": "Mozilla/5.0 (Linux; Android 6.0; Nexus 5 Build/MRA58N) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/143.0.0.0 Mobile Safari/537.36 Edg/143.0.0.0"
});

let location = new_url.header("location");
let searchid = location.match(/searchid=(\d+)/)[1];

// 分页修复（真正从第一页开始）
let url;
if (page == 0) {
    url = "https://bcshuku.com/e/search/result/?searchid=" + searchid;
} else {
    url = "https://bcshuku.com/e/search/result/index.php?page=" + (page - 1) + "&searchid=" + searchid;
}

url;
